// ── DERIVED: city-level pins for the home-page overview map ─────────────────
// One pin per unique city, at the average of its retailer coordinates.
// Home map consumes this for its <S07Map /> dots. No store-level data is
// exposed on the home page — users click through to /find for that.

export type CityPin = {
  city: string;
  state: string;
  lat: number;
  lng: number;
  count: number; // retailer count — not surfaced in UI, reserved for later
};

export const CITY_PINS: CityPin[] = (() => {
  const groups = new Map<string, Retailer[]>();
  for (const r of RETAILERS) {
    const key = `${r.city}|${r.state}`;
    const arr = groups.get(key) ?? [];
    arr.push(r);
    groups.set(key, arr);
  }
  const pins: CityPin[] = [];
  for (const [key, rs] of groups) {
    const [city, state] = key.split("|");
    const avgLat = rs.reduce((s, r) => s + r.lat, 0) / rs.length;
    const avgLng = rs.reduce((s, r) => s + r.lng, 0) / rs.length;
    pins.push({ city, state, lat: avgLat, lng: avgLng, count: rs.length });
  }
  return pins;
})();

// ── DERIVED: list of states with at least one retailer ──────────────────────
// Used by the Find search form to populate its state dropdown with only
// states that return results, rather than all 50.

export const RETAILER_STATES: string[] = [
  ...new Set(RETAILERS.map((r) => r.state)),
].sort();
